import React, { useState } from "react";
import { useNavigate } from "react-router-dom";

function SOP() {
  const navigate = useNavigate();
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  const runModule1 = async () => {
    setLoading(true);
    try {
      const res = await fetch("http://localhost:5000/module1"); // GET
      const data = await res.json();
      setResult(data);
    } catch (err) {
      console.error(err);
      alert("Backend error");
    }
    setLoading(false);
  };

  return (
    <div style={{ textAlign: "center", marginTop: "40px" }}>
      <h2>Module 1: SOP Processing</h2>

      <button onClick={runModule1}>Run Module 1</button>

      <br /><br />

      <button onClick={() => navigate("/")}>⬅ Back</button>

      {loading && <p>Processing...</p>}

      {result && result.status === "success" && (
        <div style={{ marginTop: "20px" }}>
          <h3>Output</h3>
          <p><b>NPSV Length:</b> {result.npsv_length}</p>
          <p><b>Segments Shape:</b> {result.segments_shape.join(", ")}</p>
          <p><b>Sample NPSV:</b> {result.sample_npsv.join(", ")}</p>
        </div>
      )}

      {result && result.status === "error" && (
        <p style={{ color: "red" }}>Error: {result.message}</p>
      )}
    </div>
  );
}

export default SOP;
